+        // 32-bit offsets - each offset is the END position of that string
+        str_end = readU32LE(data, offsets_start + row_idx * 4);
+        if (row_idx > 0) {
+            str_start = readU32LE(data, offsets_start + (row_idx - 1) * 4);
